<template lang="html">
  <div class="experience">
    <div class="container">
      <div class="row fillParent">
        <!-- company image -->
        <div class="col-sm-3 imgCap">
          <img
            :src="publicPath + 'imgs/resume/' + exp.logo"
            class="resumeImg unselectable"
          />
        </div>
        <div class="col-md-9">
          <!-- title and date -->
          <div class="row experienceTitle">
            <div class="col-md-12 experienceName">
              <h3>
                <a :href="exp.url">{{ exp.name }}</a> — {{ exp.position }}
              </h3>
            </div>
            <div class="experienceSubTitle col-md-12">
              <h5>
                {{ dateFormat(exp.startDate) }} -
                {{ dateFormat(exp.endDate) }} — {{ exp.location }}
              </h5>
            </div>
          </div>
          <!-- description of position -->
          <div class="row experiencePoints">
            <div class="col-md-auto">
              <span>{{ exp.summary }}</span>
              <ul v-for="line in exp.highlights" :key="line">
                <li>{{ line }}</li>
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: "Experience",
  props: {
    exp: Object
  },
  data: function() {
    return {
      publicPath: process.env.BASE_URL
    };
  },
  computed: {
    image: function() {
      return this.exp.logo;
    }
  },
  methods: {
    dateFormat: function(d) {
      let date = new Date(d);
      return `${this.$root.months[date.getMonth()]} ${date.getFullYear()}`;
    }
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>

<style lang="css" scoped>
.experienceName {
  /* remove padding for the acutal job title*/
  padding-left: 0px;
}

.experienceSubTitle {
  padding-left: 0px;
  color: var(--midCol);
}

.fillParent {
  width: 100%;
  margin-left: 0px;
}

.experiencePoints {
  margin-top: 10px;
  margin-bottom: 50px;
  font-size: 1.3em;
}

.experiencePoints ul li {
  list-style: outside;
  margin: 10px 0;
  margin-left: 3%;
}

.resumeImgContainer {
  justify-content: center;
  align-items: center;
}

.resumeImg {
  max-width: 100%;
  max-height: 100%;
  width: auto;
  height: auto;
}

.imgCap {
  max-height: 250px;
  text-align: center;
  padding-bottom: 20px;
}

.fillDiv {
  max-width: 100%;
  max-height: 100%;
  height: auto;
  width: auto;
}

a {
  color: var(--lightCol);
  /*text-underline-position: ;*/
  text-decoration-thickness: 15%;
  text-underline-offset: 0.3em;
}

a:hover {
  color: gray;
}
</style>
