<template>
  <div class="work">
    <h1 class="headerText text-center">Work</h1>
    <!-- filter -->
    <div class="container" style="width: 100%;">
      <div class="row justify-content-md-center text-center filterList">
        <div
          class="col-md-2"
          v-for="(filter, index) in filters"
          :key="filter"
          :class="{ 'col-md-offset-1': index == 0 }"
        >
          <h4 :id="filter" class="filterText" v-on:click="activate">
            {{ filter }}
          </h4>
        </div>
      </div>
    </div>

    <!-- work items in grid -->
    <div class="container" id="workGridContainer">
      <!-- allow for this.chunkSize vids per row -->
      <div
        class="row "
        v-for="(chunk, index) in workChunked"
        :key="'workChunk' + index"
      >
        <!-- for items in this row -->
        <div
          class="WorkItem col-lg-4"
          v-for="item in chunk"
          :key="'workItem_' + item.name"
          v-on:click="storeState"
        >
          <router-link :to="{ path: getURL(item.name) }">
            <div class="thumbContainer">
              <img
                class="thumbnail"
                :src="getImage(item.titleImage)"
                :alt="item.name"
              />
              <div
                class="overlay"
                :style="{ 'background-color': getColor(item.bgColor) }"
              >
                <div
                  class="hoverText "
                  :style="{ color: getFontColor(item.bgColor) }"
                >
                  <h4>{{ item.hoverText }}</h4>
                </div>
              </div>
            </div>
            <h3 class="workItemTitle">{{ item.name }}</h3>
          </router-link>
        </div>
      </div>
    </div>
  </div>
</template>

<script type="text/javascript">
import workjson from "@/assets/data/work.json";
export default {
  data: function() {
    return {
      workList: workjson,
      publicPath: process.env.BASE_URL,
      filters: ["Featured", "All", "Creative Code", "3D", "2D"],
      activeTag: "Featured",
      activeEl: null,
      containerEl: null,
      currentFilter: "Featured",
      chunkSize: 3
    };
  },
  computed: {
    workChunked: function() {
      let arr;
      if (this.activeTag == "All") {
        arr = Object.values(this.workList);
      } else {
        arr = this.filterObj(this.workList, this.activeTag);
      }
      return this.chunkArray(this.chunkSize, arr);
    },
    lightCol: function() {
      let style = getComputedStyle(document.body);
      return style.getPropertyValue("--lightCol");
    },
    darkCol: function() {
      let style = getComputedStyle(document.body);
      return style.getPropertyValue("--darkCol");
    }
  },
  methods: {
    // return thumbnail image based for name
    getImage: function(name) {
      return this.publicPath + "imgs/workThumbnails/" + name;
    },
    // get the color from json to hex
    getColor: function(rgb) {
      return (
        "#" +
        rgb
          .map(x => {
            const hex = x.toString(16);
            return hex.length === 1 ? "0" + hex : hex;
          })
          .join("")
      );
    },
    // return either white or black font based on background color
    getFontColor: function(rgb) {
      return rgb[0] * 0.299 + rgb[1] * 0.587 + rgb[2] * 0.114 > 186
        ? this.darkCol
        : this.lightCol;
    },
    // get url for the project by converting to path
    getURL: function(name) {
      const space = / /g;
      const slash = /\//g;
      return (
        "work/" +
        name
          .replace(space, "-")
          .replace(slash, "-")
          .toLowerCase()
      );
    },
    // chunk the array into 2d array with element size chunk
    chunkArray: function(chunk, arr) {
      let out = [];
      for (let i = 0; i < arr.length; i += chunk) {
        out.push(arr.slice(i, i + chunk));
      }
      return out;
    },
    // return whether this object has the tag
    filterObj: function(obj, tag) {
      tag = tag.toLowerCase();
      let result = [],
        key;
      for (key in obj) {
        if (obj[key].tags.includes(tag)) {
          result.push(obj[key]);
        }
      }
      return result;
    },
    // when going to a project store what the current filter is
    storeState: function() {
      localStorage.filter = this.activeEl.id;
    },
    // activate the filtered list
    activate: function(event) {
      // if there is a change in content
      if (this.activeEl != null && event.target != this.activeEl) {
        this.activeTag = event.target.id;
        // switch active
        this.activeEl.classList.remove("active");
        event.target.classList.add("active");
        // fade in the new content
        this.containerEl.classList.remove("fadeIn");
        this.containerEl.classList.add("fadeOut");
        setTimeout(() => {
          this.containerEl.classList.remove("fadeOut");
          this.containerEl.classList.add("fadeIn");
        }, 300);
      }
      this.activeEl = event.target;
      // store state of filter
      // localStorage.filter = this.activeEl.id;
    }
  },
  mounted: function() {
    if (localStorage.filter != "") {
      this.activeEl = document.getElementById(localStorage.filter);
      this.activeTag = localStorage.filter;
      localStorage.filter = "";
    } else {
      this.activeEl = document.getElementById("Featured");
      this.activeTag = "Featured";
    }
    // bold the correct filter
    this.activeEl.classList.add("active");
    this.containerEl = document.getElementById("workGridContainer");
  },
  metaInfo() {
    return {
      title: "Work",
      meta: [
        { name: "description", content: "A collection of my portfolio work" }
      ]
    };
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>

<style lang="css" scoped>
/* title text */

.WorkItem {
  margin-bottom: 1em;
  position: relative;
}

.row {
  padding-bottom: 1em;
}

.container-fluid {
  padding: 0px;
}

.thumbContainer {
  width: 100%;
  position: relative;
  display: inline-block;
}

/* content styling */

.thumbnail {
  width: 100%;
  object-fit: contain;
  height: 300px;
  position: relative;
  display: inline-block;
}

.workItemTitle {
  font-weight: 300;
  padding-top: 0.25em;
}

#workGridContainer {
  padding-bottom: 2em;
}

/* hover effects  */

.overlay {
  position: absolute;
  top: 0;
  bottom: 0;
  left: 0;
  right: 0;
  height: 100%;
  width: 100%;
  opacity: 0;
  transition: 0.2s ease;
  display: inline-block;
}

@media (hover: hover) {
  .thumbContainer:hover .overlay {
    opacity: 1;
    transition: opacity 0.3s ease-in-out;
  }
}

a {
  color: inherit;
  text-decoration: inherit; /* no underline */
}
a:link {
  text-decoration: none;
}

a:visited {
  text-decoration: none;
}

a:hover {
  text-decoration: none;
  color: inherit;
}

a:active {
  text-decoration: none;
}

.hoverText {
  color: white;
  font-size: 20px;
}

.hoverText h4 {
  margin: 0;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

/* filter list */
.filterList {
  font-size: 1.2em;
  padding-bottom: 1.5em;
}

.filterText {
  font-weight: 350;
  cursor: pointer;
  box-sizing: border-box;
  color: var(--midCol);
}

.active {
  font-weight: 500;
  color: var(--lightCol);
}

.filterText:hover,
:before,
:after {
  text-decoration: underline;
}

/* animations */

.fadeOut {
  opacity: 0;
}

.fadeIn {
  transition: ease 0.25s;
  opacity: 1;
}
</style>
