<template lang="html">
  <div id="projectContainer" style="margin-bottom: 2em;">
    <!-- project info -->
    <div class="container info">
      <div class="row justify-content-center">
        <h1
          id="page-title"
          class="col-lg-auto title text-wrap"
          v-html="page.title"
        ></h1>
        <div class="col-lg-5">
          <div class="subtitle">
            <h2>{{ page.subtitle }}</h2>
            <h2 class="tools">{{ tools }}</h2>
          </div>
        </div>
      </div>
    </div>
    <!-- render page content -->
    <div
      class="content"
      v-for="(part, index) in page.content"
      :key="id + index"
    >
      <!-- show videos -->
      <div v-if="part.type === 'video' && part.local === true">
        <div class="container">
          <div class="row justify-content-center">
            <video
              class="localVideo"
            
              v-if="part.local === true"
              :autoplay="part.autoplay"
              :loop="part.loop"
              :muted="part.autoplay"
              :controls="!('autoplay' in part)"
            >
              <source :src="getLocalVideo(part.src)" type="video/mp4" />
            </video>
          </div>
        </div>
      </div>
      <!-- use vimeo for the video -->
      <div
        class="videoWrapper" v-bind:id="part.src"
        v-if="part.type === 'video' && !('local' in part)"
      >
        <iframe
          :src="getVideoLink(part)"
          frameborder="0"
          class="videoSettings"
          allow="autoplay; fullscreen"
          allowfullscreen
        >
        </iframe>
      </div>
      <!-- show text -->
      <div class="textContent" v-else-if="part.type === 'text'">
        <div class="container">
          <div class="row">
            <p class="col-md-12" v-html="part.body"></p>
          </div>
        </div>
      </div>
      <!-- show header -->
      <div v-else-if="part.type === 'header'">
        <div class="container">
          <div class="row">
            <h1 class="col-md-12 header">{{part.body}}</h1>
          </div>
        </div>
      </div>
      <!-- show list -->
      <div class="textContent" v-else-if="part.type === 'list'">
        <div class="container">
          <div class="row">
            <p>
              <span class="col-md-12 listbody">{{part.body}}</span>
            <ul>
              <li
                class="col-lg-12 mx-auto"
                v-for="copy in part.list"
                :key="copy"
              ><span>{{copy}}</span></li>
            </ul>
            </p>
          </div>
        </div>
      </div>

      <!-- show images -->
      <div class="imageContainer" v-else>
        <div class="container">
          <div class="row">
            <img
              class="col-lg-12 projImg mx-auto"
              v-for="imgPack in part.images"
              :key="imgPack.path"
              :src="getImage(imgPack.path)"
              :alt="getAltText(imgPack.path)"
              :style="setResolution(imgPack.res, imgPack.forceRes)"
            />
          </div>
        </div>
      </div>
    </div>
    <div class="container top-button" v-show="longPage">
      <div class="text-center">
       <button type="button" class="push-button" v-scroll-to="'#navigation-container'">Back to top</button>
      </div>
    </div>
  </div>
</template>

<script src="https://player.vimeo.com/api/player.js"></script>
<script>
import Vue from 'vue' 
import VueAxios from 'vue-axios'
import axios from 'axios'

function toTitleCase(str) {
  return str.replace(/\w\S*/g, function(txt) {
    return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
  });
}

export default {
  name: "projectPage",
  props: {
    id: String,
    publicPath: String
  },
  data: function() {
    return {
      contentDiv: null
    };
  },
  computed: {
    page: function() {
      return require("@/assets/projects/" + this.id + ".json");
    },
    tools: function() {
      return this.page.tools.join(" | ");
    },
    maxVideoHeight: function() {
      let windowHeight = window.innerHeight;
      return `${windowHeight > 1080 ? 1080 : windowHeight * .95}px`;
    },
    longPage: function() {
      if (this.contentDiv !== null){
        return window.innerHeight < this.contentDiv.scrollHeight;
      }
      return false;
    }
  },
  methods: {
    getVideoLink: function(part) {
      let id = part.src;
      let autoplay = part.hasOwnProperty("autoplay") ? 1 : 0;
      let loop = part.hasOwnProperty("loop") ? 1 : 0;

      return (
        "https://player.vimeo.com/video/" +
        id +
        "?color=ffffff&portrait=0" +
        "&autoplay=" +
        autoplay +
        "&loop=" +
        loop +
        "&muted=" +
        autoplay
      );
    },
    getImage: function(path) {
      return this.publicPath + "imgs/projectImages/" + path;
    },
    getLocalVideo: function(path) {
      return this.getImage(path);
    },
    isOdd: function(i) {
      return i % 2 == 1;
    },
    // get the name of the file and use it as the alt text
    getAltText: function(path) {
      let noExt = path.substring(0, path.lastIndexOf(".") + 1);
      return noExt.split("/").slice(-1);
    },
    // set the max resolution for this image
    setResolution: function(res, force) {
      let windowHeight = window.innerHeight;
      if (res[1] > windowHeight && force === undefined) {
        let ratio = res[1] / windowHeight;
        res[0] /= ratio;
        res[1] /= ratio;
      }
      return `max-width: ${res[0]}px; max-height: ${res[1]}px;`;
    },
    isPortrait: function(part){
      return Vue.axios.get(`https://vimeo.com/api/oembed.json?url=https://vimeo.com/${part.src}`)
      .then(function (response) {
        console.log();
        return Number(response.data.height) > Number(response.data.width);
      })
      .catch(function (error) {
        // handle error
        console.log(error);
        return false;
      });
    }
  },
  mounted() {
    this.contentDiv = document.getElementById("projectContainer");
    // make sure that portrait videos are big enough
    for( let i in this.page.content){
      let entry = this.page.content[i];
      if (entry.type === 'video' && !entry.local){
        console.log(entry);
        let portrait = this.isPortrait(entry);
        portrait.then( (flag) => {
          console.log(flag)
          if (flag){
            let wrapper = document.getElementById(this.page.content[i].src);
            wrapper.classList.add("portrait-vid");
          }
        });
        
      }
    }
  },
  metaInfo() {
    return {
      title: this.page.title,
      meta: [{ name: "description", content: this.page.subtitle }]
    };
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>

<style lang="css" scoped>
/* ////  page info  ///// */
.title {
  font-size: 3em;
  padding-top: 0%;
  max-width: 50%;
  padding-bottom: 0%;
}

.subtitle {
  width: 100%;
  position: relative;
  padding-top: 0.25em;
}
.subtitle > h2 {
  font-size: 1.25em;
  font-weight: 300;
}
.tools {
  color: var(--midCol);
}
.info {
  padding-top: 1.5em;
}

/* ////  videos  ///// */
.videoSettings {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
}

/* style="padding:54.06% 0 0 0;position:relative;" */
.videoWrapper {
  margin-top: 1em;
  margin-bottom: 1em;
  padding: 33% 0 0 0;
  position: relative;
  /* margin: auto; */
  /*margin-left: 15%;*/
  display: block;
  /*    max-height: 75%;  
    max-width: 75%;*/

  height: auto;
  width: auto;
  overflow: hidden;
}

.portrait-vid {
  padding: 50% 0 0 0;
}

.localVideo {
  max-width: 100%;
/*  max-height: 1080px;*/
  max-height: 98vh;
/*  height: auto;*/
  position: relative;
  margin-top: 1em;
  margin-bottom: 1em;
  display: block;
  overflow: hidden;
  background-color: transparent;
}

/* ////  text  ///// */
.textContent {
  font-size: 1.25em;
  padding-top: 1em;
  padding-bottom: 1em;
}

.header {
  padding-top: 1em !important;
  padding-bottom: .5em !important;
  margin-bottom: 0px !important;
}

/* ////  images  ///// */
.projImg {
  padding-top: 1em;
  padding-bottom: 1em;
  max-width: 100%;
}

ul {
  padding-left: 20px;
}

li:before {
  content: '\2014';
  position: absolute;
  margin-left: -20px;
}

li span {
  position: relative;
  left: 10px;
  margin-right: -10px;
}

.listbody {
  display: inline-block;
}

@media (max-width: 500px) {
  .portrait-vid {
    padding: 100% 0 0 0;
  }

  .projImg {
    max-width: 100%;
    max-height: 100%;
  }

  .title {
    max-width: 100%;
  }
}

.top-button {
  padding-bottom: 1em;
}
</style>
