<template lang="html">
  <div id="skills">
    <div v-for="category in skills" :key="category.name">
      <h3 class="text-center">{{ category.name }}</h3>
      <div class="container" style="width:100%; margin-bottom: 50px;">
        <div class="row">
          <!-- skill in row -->
          <div
            class="col-sm-3 col-4 p-3 text-center"
            v-for="skill in category.keywords"
            :key="category + skill"
          >
            <img :src="getImage(skill)" class="skillImg unselectable" />
            <h3 class="skillTitle">{{ skill }}</h3>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import imageMap from "@/assets/data/skills-image-map.json";

export default {
  props: {
    skills: Array
  },
  data: function() {
    return {
      publicPath: process.env.BASE_URL,
      imgmap: imageMap
    };
  },
  methods: {
    getImage: function(name) {
      return this.publicPath + "imgs/resume/" + this.imgmap[name];
    }
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>

<style lang="css" scoped>
.skillTitle {
  font-size: 0.8em;
  padding-top: 0.5em;
  color: var(--midCol);
}

.skillImg {
  height: 3em;
  width: auto;
}
</style>
