let p5;
let header, footer;
let width, height;
let canvas;

const Matter = require("matter-js");

const Engine = Matter.Engine,
  Composite = Matter.Composite,
  Body = Matter.Body,
  Bodies = Matter.Bodies;

// matter vars
var engine;
var world;
let topWall, leftWall, rightWall, bottomWall;
let mouseCollider;
// array of all the balls and array for balls to remove
var balls = [];
var dead = [];
// ball constants
const MAX_SIZE = 80;
const MOUSE_SIZE = MAX_SIZE * .5;
const MIN_SIZE = 10;
const BALL_COLORS = ["#7785AC", "#F0803C", "#AECFDF", "#907F9F"];
let MAX_BALLS = 100; // total number of balls allowed
const START_BALLS = 60;
let isSetup = false; // flag to know if this app is ready to be used

// spawn values 
let timer = 0;
const SPAWN_TIME = 5000; // spawn new balls after 5 seconds



class Ball {

	constructor(initPosX, initPosY, _radius,rot=null) {
		this.rad = _radius;
		this.body = Bodies.circle(initPosX, initPosY, this.rad/2.0);
		this.color = BALL_COLORS[p5.floor(p5.random(0, 4))];
		this.kill = false;
		this.dead = false;
		let bodyOptions = {
			friction: 0,
			restitution: 1,
			frictionAir: 0
		};
		Composite.add(world, this.body, bodyOptions);
		if (rot != null){
			Body.setAngularVelocity( this.body, rot);
		}
	}

	render() {
		let pos = this.body.position;
		let angle = this.body.angle;
		p5.push();
		p5.translate(pos.x, pos.y);
		p5.noStroke();
		p5.fill(this.color);
		p5.circle(0, 0, this.rad);
		p5.pop();
		if (this.kill) {
			this.rad *= .95;
			this.dead = this.rad < .1;
		}
	}

	getSpeed() {
		return Matter.Body.getAngularSpeed(this.body);
	}
}

let addBall = () => {
	
	if (p5.mouseY < height && p5.mouseY >= 0){
		balls.push(new Ball(p5.mouseX, p5.mouseY, p5.random(MIN_SIZE, MAX_SIZE), p5.random(-Math.PI/6, Math.PI/6)));
		if (balls.length > MAX_BALLS){
			for (let i = 0; i < balls.length - MAX_BALLS; i++){
				balls[i].kill = true;
			}
		}
	}
};

let addBalls = (numSpots, numBalls) => {
	// numspots is the number of positions to distribute the numBalls
	let seedPoss = [];
	for (let i = 0; i < numSpots; i++){
		seedPoss.push([p5.random(.2,.8) * p5.windowWidth, p5.random(.2, .8) * p5.windowHeight]);
	}
	let seedX = p5.windowWidth * .7;
	let seedY = p5.windowHeight * .5;
	
	let indexOffset = p5.round(p5.random());
	for (let i = 0; i < numBalls; i++){
		let index = p5.floor(p5.random(numSpots));
		let seedPos = seedPoss[index];
		balls.push( new Ball(seedPos[0] + p5.random(), seedPos[1] + p5.random(), p5.random(MIN_SIZE, MAX_SIZE), (2 * (index + indexOffset % 2) -1) * Math.PI/60));
	}
	if (balls.length > MAX_BALLS){
		for (let i = 0; i < balls.length - MAX_BALLS; i++){
			balls[i].kill = true;
		}
	}
}

let setBoundaries = (width, height) => {
	let midX = p5.windowWidth / 2;
	let midY = p5.windowHeight / 2;
	topWall = Bodies.rectangle(midX, 0, width, 1, { isStatic: true });
	leftWall = Bodies.rectangle(0, midY, 1, height, { isStatic: true });
	rightWall = Bodies.rectangle(width, midY, 1, height, { isStatic: true });
	bottomWall = Bodies.rectangle(midX, height, width, 1, { isStatic: true });
	Composite.add(world, [topWall, leftWall, rightWall, bottomWall]);
}

export function main(_p5) {
	p5 = _p5;

	p5.windowResized = () => {
		console.log("resize canvas");
		canvas.position(0, header.offsetHeight);
		width = p5.windowWidth;
		height = p5.windowHeight - header.offsetHeight;
		p5.resizeCanvas(
		  width,
		  height
		);

		Composite.remove(world, [topWall, leftWall, rightWall, bottomWall]);
		setBoundaries(width, height);
	};

	p5.setup = () => {
		// get size based on displayed space
		header = document.getElementById("navContainer");
		// footer = document.getElementById("footer");
		width = p5.windowWidth;
		height = p5.windowHeight - header.offsetHeight;
		canvas = p5.createCanvas(
		  width,
		  height
		);
		canvas.style("z-index", "-1");

		// set max balls
		if (width < 1080) {
			MAX_BALLS = START_BALLS;
		} 

		// setup engine
		engine = Engine.create();
		engine.world.gravity.y = 0.0;
		engine.timing.timeScale = .5;
		engine.velocityIterations = 20;
		world = engine.world;
		
		// add boundaries
		setBoundaries(width, height);

		mouseCollider =  Bodies.circle(p5.mouseX, p5.mouseY, MOUSE_SIZE/2);
		let bodyOptions = {
			friction: 0,
			restitution: 1,
			frictionAir: 0
		};
		Composite.add(world, mouseCollider, bodyOptions);

		// spawn the initial balls
		balls.length = 0;
		addBalls(2, START_BALLS);
		p5.describe('An interactive and colorful particle system');
		isSetup = true;
	};

	p5.draw = () => {
		p5.clear()
		// if we need to spawn more balls
		if (p5.millis() >= SPAWN_TIME + timer) {
			timer = p5.millis();
			addBalls(1, 15);
		}
		// update the physics
		Engine.update(engine);
		dead.length = 0;
		// render balls
		for (var i = 0; i < balls.length; i++) {
			balls[i].render();

			// if this is dead add to kill list
			if (balls[i].dead){
				dead.push(i);
			}
		}
		// free up dead balls
		for (var i = dead.length -1; i >= 0; i--){
			let index = dead[i];
			Composite.remove(world, balls[index].body);
			balls.splice(index, 1);
		}
	};

	// add on single click
	p5.mousePressed = () => {
		addBall();
	};
	// add on drag
	p5.mouseDragged = () => {
		addBall();
	};

	p5.mouseMoved = () => {
		if (isSetup){
			Body.setPosition(mouseCollider, Matter.Vector.create(p5.mouseX, p5.mouseY));
		}
	}
}
