<template lang="html">
  <div class="playground col-lg-12 mx-auto">
    <h1 class="headerText text-center">Playground</h1>
    <h3 class="text-center subtitle">
      Various experiments and random elements I've been playing around with.
    </h3>

    <div class="grid">
      <div class="grid-sizer"></div>
      <div
        class="grid-item"
        v-for="asset in assets.slice(0, assetMax)"
        :key="asset.path"
        data-toggle="modal"
        data-target="#popupModal"
        :data-path="asset.path"
        :data-title="asset.title"
        :data-type="asset.type"
      >
        <img v-if="asset.type === 'image'" class="content" :src="asset.path" />

        <video
          v-if="asset.type === 'video'"
          class="grid-video content"
          autoplay
          loop
          muted
        >
          <source :src="asset.path" type="video/mp4" />
        </video>
      </div>
    </div>
    <div class="container info">
      <div class="row justify-content-center">
        <button
          @click="loadMore"
          class="col-md-3 load-button text-center"
          v-show="assetMax !== assets.length"
        >
          Load More
        </button>
      </div>
    </div>

    <!-- Modal -->
    <div
      class="modal fade"
      id="popupModal"
      tabindex="-1"
      role="dialog"
      aria-hidden="true"
    >
      <div class="modal-dialog modal-dialog-centered" role="document">
        <div class="modal-content align-middle">
          <div class="modal-header">
            <h5 class="modal-title" id="popupModalLabel">Experiment Name</h5>
            <button
              type="button"
              class="close"
              data-dismiss="modal"
              aria-label="Close"
            >
              <span aria-hidden="true">&times;</span>
            </button>
          </div>
          <div class="modal-body">
            <img v-show="modalImg" id="modal-image" class="pop-up-image" />
            <video
              v-show="!modalImg"
              id="modal-video"
              class="pop-up-image"
              controls
            >
              <source id="modal-source" type="video/mp4" />
            </video>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
// import playgroundItem from "@/components/playground/playgroundItem.vue";
import Masonry from "masonry-layout";
import playgroundjson from "@/assets/data/playground.json";
import imagesLoaded from "imagesloaded";
import $ from "jquery";

export default {
  name: "playground",
  data: function() {
    return {
      publicPath: process.env.BASE_URL,
      modalImg: true,
      msnry: 0,
      assetMax: 0,
      gutter: 15
    };
  },
  computed: {
    assets: function() {
      let myAssets = [];
      playgroundjson["data"].forEach(element => {
        let title = element.title;
        // add in the videos
        let myVids = element.videos;
        if (myVids) {
          for (let i = myVids.length - 1; i >= 0; i--) {
            myAssets.push({
              title: title,
              path: this.getImage(myVids[i]),
              type: "video"
            });
          }
        }

        // add in the image files
        let myImgs = element.images;
        if (myImgs) {
          for (let i = myImgs.length - 1; i >= 0; i--) {
            myAssets.push({
              title: title,
              path: this.getImage(myImgs[i]),
              type: "image"
            });
          }
        }
      });
      return myAssets;
    },
    allVideos: function() {
      return document.getElementsByClassName("grid-video");
    }
  },
  mounted: function() {
    // initialize the masonry grid
    let elem = document.querySelector(".grid");
    imagesLoaded(elem, () => {
      this.msnry = new Masonry(elem, {
        // options
        itemSelector: ".grid-item",
        columnWidth: ".grid-sizer",
        percentPosition: true,
        gutter: this.gutter
      });
      this.layoutVids();
    });

    // update the number assets viewed
    this.assetMax = Math.min(10, this.assets.length);

    // add modal for image viewing
    $("#popupModal")
      .on("show.bs.modal", event => {
        $("#popupModal").css("z-index", 1001);
        let button = $(event.relatedTarget); // Button that triggered the modal
        let type = button.data("type");
        // show either an image or a video
        this.modalImg = type === "image";
        // update content
        if (type === "image") {
          document
            .querySelector("#modal-image")
            .setAttribute("src", button.data("path"));
        } else if (type === "video") {
          let vid = document.querySelector("#modal-video");
          let source = document.querySelector("#modal-source");
          vid.pause();
          source.setAttribute("src", button.data("path"));
          vid.load();
          vid.play();
        }
        // set title text
        $("#popupModalLabel").html(button.data("title"));

        // pause background videos
        this.setGridPlayback(false);
      })
      .on("hidden.bs.modal", () => {
        $("#popupModal").css("z-index", -1001);
        // on hidden modal stop playing the video and unload it
        let vid = document.querySelector("#modal-video");
        vid.pause();
        vid.removeAttribute("src"); // empty source
        vid.load();
        // resume grid videos
        this.setGridPlayback(true);
      });
  },
  methods: {
    getImage: function(path) {
      return this.publicPath + "imgs/playground/" + path;
    },
    getAltText: function(path) {
      let noExt = path.substring(0, path.lastIndexOf(".") + 1);
      return noExt.split("/").slice(-1);
    },
    layoutVids: function() {
      for (var i = this.allVideos.length - 1; i >= 0; i--) {
        let vid = this.allVideos[i];
        vid.addEventListener("loadeddata", () => {
          // console.log(`got ${event}`);
          this.msnry.layout();
        });
      }
    },
    setGridPlayback: function(play) {
      for (var i = this.allVideos.length - 1; i >= 0; i--) {
        if (play) {
          this.allVideos[i].play();
        } else {
          this.allVideos[i].pause();
        }
      }
    },
    loadMore: function() {
      let newNum = Math.min(this.assetMax + 10, this.assets.length);
      let showNew = newNum !== this.assetMax;
      this.assetMax = newNum;
      if (showNew) {
        imagesLoaded(document.querySelector(".grid"), () => {
          this.msnry.reloadItems();
          this.msnry.layout();
          this.layoutVids();
        });
      }
    }
  },
  // components: {
  // 	playgroundItem
  // },
  metaInfo() {
    return {
      title: "Playground",
      meta: [
        {
          name: "description",
          content:
            "Various experiments and random elements I've been playing around with"
        }
      ]
    };
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>
<style lang="css" scoped>
.subtitle {
  padding-bottom: 3em;
}

.load-button {
  margin-bottom: 3em;
  color: white;
  border-radius: 8px;
  background-color: var(--darkCol);
  border: 2px solid white;
  transition-duration: 0.2s;
  padding: 1em;
}

.load-button:hover {
  background-color: var(--lightCol); /* Green */
  color: var(--darkCol);
}

.load-button:active {
  background-color: var(--highlightCol);
}

.grid {
  width: 90%;
  margin-left: 5%;
  padding-bottom: 3em;
  /*	width: 100%;*/
}

.grid-sizer,
.grid-item {
  width: calc(33.33% - 30px / 3);
}

.grid-item {
  margin-bottom: 15px;
}

.content {
  width: 100%;
  height: 100%;
}

.pop-up-image {
  max-height: 90vh;
  max-width: 95vw;
}

.modal-dialog {
  /* Width */
  max-width: 100%;
  width: auto !important;
  display: inline-block;
}

.modal {
  z-index: -1001;
  display: flex !important;
  justify-content: center;
  align-items: center;
  background-color: rgba(255, 255, 255, 0.2);
}

.modal-content {
  background-color: var(--darkCol);
  color: white;
}

.modal-backdrop {
  opacity: 0.5 !important;
}

.modal-open .modal {
  /*  z-index: 2000;*/
  overflow: hidden;
}

.close {
  color: var(--lightCol);
}
</style>
