<template lang="html">
  <div id="sketchContainer"></div>
</template>

<script
  src="https://cdnjs.cloudflare.com/ajax/libs/gl-matrix/2.8.1/gl-matrix-min.js"
  integrity="sha512-zhHQR0/H5SEBL3Wn6yYSaTTZej12z0hVZKOv3TwCUXT1z5qeqGcXJLLrbERYRScEDDpYIJhPC1fk31gqR783iQ=="
  crossorigin="anonymous"
  defer
></script>

<script>
const P5 = require("p5");

export default {
  data: function() {
    return {
      canvas: null,
      now: window.performance.now()
    };
  },
  methods: {},
  mounted() {
    let sketch = require("@/assets/js/ballSketch.js");
    this.canvas = new P5(sketch.main, "sketchContainer");
  },
  beforeDestroy() {
    // cleanup by removing p5 elements. If the user comes back to this page it will be reinited in mounted()
    this.canvas.remove();
    this.canvas = null;
    return;
  }
};
</script>

<style lang="css" scoped>
#sketchContainer {
}
</style>
